//IE Check
	function is_ie_browser() {
		// 1. 取得 User Agent，兼容舊版 PHP 的全域變數取法
		$user_agent = '';
		
		if (isset($_SERVER['HTTP_USER_AGENT'])) {
			$user_agent = $_SERVER['HTTP_USER_AGENT'];
		} elseif (isset($GLOBALS['HTTP_SERVER_VARS']['HTTP_USER_AGENT'])) {
			// 針對 PHP 4.1 以前或某些特殊設定的舊環境
			$user_agent = $GLOBALS['HTTP_SERVER_VARS']['HTTP_USER_AGENT'];
		}
	
		// 若抓不到 UA，預設回傳 false
		if (empty($user_agent)) {
			return false;
		}
	
		// 2. 轉為小寫，方便比對 (PHP 4 支援 strtolower)
		$ua = strtolower($user_agent);
	
		// 3. 判斷邏輯
		// IE 11 的特徵是 'trident' 且通常沒有 'msie' (微軟為了防止舊網站誤判而移除了 msie)
		// IE 6~10 的特徵都有 'msie'
		// 只要有 'msie' 或是 'trident'，基本上就是 IE 家族 (包含相容模式)
		// 注意：Edge (舊版 EdgeHTML) 和 Edge (Chromium) 都不含 trident 或 msie
		
		// 使用 strpos 檢查 (注意：必須使用 !== false，因為位置可能是 0)
		$is_msie = strpos($ua, 'msie') !== false;
		$is_trident = strpos($ua, 'trident') !== false;
	
		if ($is_msie || $is_trident) {
			return true;
		}
	
		return false;
	}

//File 加強版
	function file_curl($api_url, $isFile = true) {
		if (!function_exists('curl_init')) {
			return false;
		}
	
		$ch = curl_init();
			curl_setopt($ch, CURLOPT_URL, $api_url);
			curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
			curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 10);
			curl_setopt($ch, CURLOPT_TIMEOUT, 30);
			$output = curl_exec($ch);
			$error  = curl_error($ch);
		curl_close($ch);
		if ($output === false) {
			return false;
		}
		if ($isFile) {
			$output = str_replace(array("\r\n", "\r"), "\n", $output);
			$returndata = explode("\n", $output);
		} else {
			$returndata = $output;
		}
		return $returndata;
	}


